// Gatsby supports TypeScript natively!
import React, { useState, useEffect } from "react"
import { graphql } from "gatsby"

import Bio from "../components/bio"
import { PageDataInterface } from "../interfaces/page"
import { default as BlogCardList } from "../components/blog/card-list"
import Layout from "../components/layout"
import SEO from "../components/seo"

interface FrontmatterInterface {
  date: string
  description: string
  img: {
    publicURL: string
  }
  tags: Array<string>
  title: string
}

interface Fields {
  slug: string
}

export interface PostInterface {
  excerpt: string
  frontmatter: FrontmatterInterface
  fields: Fields
  timeToRead: number
}

interface QueryData {
  allMarkdownRemark: {
    edges: {
      node: PostInterface
    }[]
  }
}

interface BlogInterface {
  data: QueryData
}

interface LocationState {
  key: string
  tags: Array<string>
}

const BlogIndex: React.FunctionComponent<
  BlogInterface & PageDataInterface
> = props => {
  const getTags = (tags: Array<string> = []): Array<string> => {
    return tags.concat(
      props.location.state ? (props.location.state as LocationState).tags : []
    )
  }
  const [tags, setTags] = useState(getTags())

  const filterPosts = (tags: Array<string>) => {
    const posts = props.data.allMarkdownRemark.edges.map(edge => edge.node)
    return tags.length == 0
      ? posts
      : posts.filter(post =>
          post.frontmatter.tags.some(tag => tags.includes(tag))
        )
  }
  const [posts, setPosts] = useState(filterPosts(tags))

  const updateTags = (tags: Array<string>) => {
    setTags(tags)
    setPosts(filterPosts(tags))
  }

  useEffect(() => {
    // TODO: Make this a little less hacky
    window.history.pushState(null, "")
  })

  return (
    <Layout title="Blog">
      <SEO title="All Posts" />
      <BlogCardList posts={posts} tags={tags} updateTags={updateTags} />
      <Bio />
    </Layout>
  )
}

export default BlogIndex

export const pageQuery = graphql`
  query {
    allMarkdownRemark(sort: { fields: [frontmatter___date], order: DESC }) {
      edges {
        node {
          excerpt
          fields {
            slug
          }
          frontmatter {
            date(formatString: "MMMM DD, YYYY")
            description
            img {
              publicURL
            }
            tags
            title
          }
          timeToRead
        }
      }
    }
  }
`
