import React from "react"
import Tag from "./tag"
import { default as StaticTag } from "./static-tag"

interface TagsInterface {
  tags: Array<string>
  selectedTags?: Array<string> | null
  updateTags?: (tags: Array<string>) => void | null
}

/**
 * Renders a list of tags, tags can be static tags (without the updateTags callback), or tags with this added functionality
 * @param props <TagsInterface>
 */
const Tags: React.FunctionComponent<TagsInterface> = props => {
  return (
    <>
      {props.tags.map((tag: string, index: number) =>
        props.selectedTags && props.updateTags ? (
          <Tag
            tag={tag}
            key={index}
            selectedTags={props.selectedTags}
            updateTags={props.updateTags}
          />
        ) : (
          <StaticTag tag={tag} />
        )
      )}
    </>
  )
}

export default Tags
