import React from "react"

interface CardHeaderInterface {
  date: string | null
}

const CardHeader: React.FunctionComponent<CardHeaderInterface> = props => {
  return (
    <header>
      <div className="card-header">{props.children}</div>
      {props.date && (
        <small className="bg-gray-300 pill text-sm">{props.date}</small>
      )}
    </header>
  )
}

export default CardHeader
