import React from "react"
import { Link } from "gatsby"

export type StaticTagInterface = {
  tag: string
}

const Tag: React.FunctionComponent<StaticTagInterface> = props => {
  return (
    <small className="bg-red-200 pill text-sm ml-1">
      <Link to="/blog" state={{ tags: [props.tag] }}>
        {props.tag}
      </Link>
    </small>
  )
}

export default Tag
