import React from "react"
import Tags from "../tags/tags"

interface CardFilterInterface {
  selectedTags: Array<string>
  updateTags: (tags: Array<string>) => void
}

const CardFilter: React.FunctionComponent<CardFilterInterface> = props => {
  const clearTags = (
    event: React.MouseEvent<HTMLButtonElement, MouseEvent>
  ) => {
    props.updateTags([])
  }

  return (
    <div className="flex justify-around flex-wrap">
      <div className="flex-auto w-4/5">
        {props.selectedTags.length > 0 && (
          <Tags
            selectedTags={props.selectedTags}
            tags={props.selectedTags}
            updateTags={props.updateTags}
          />
        )}
      </div>
      <div className="flex-auto w-5/5">
        <button
          className="btn w-full text-center float-right"
          onClick={clearTags}
        >
          Clear Filters
        </button>
      </div>
    </div>
  )
}

export default CardFilter
