import React from "react"
import { Link } from "gatsby"
import { PostInterface } from "../../pages/blog"

import CardContent from "./card-content"
import CardFooter from "./card-footer"
import CardHeader from "./card-header"
import CardImage from "./card-image"

import Tags from "../tags/tags"

interface CardInterface {
  post: PostInterface
  tags: Array<string>
  updateTags: (tags: Array<string>) => void
}

const Card: React.FunctionComponent<CardInterface> = props => {
  const previewImage = props.post.frontmatter.img
  const postTags = props.post.frontmatter.tags || []
  const title = props.post.frontmatter.title || props.post.fields.slug

  return (
    <div className="w-full sm:w-1/2 md:w-1/3 lg:w-1/3 xl:w-1/3 mb-4 px-2">
      <div className="card">
        <article key={props.post.fields.slug}>
          {previewImage && (
            <Link to={props.post.fields.slug}>
              <CardImage src={previewImage.publicURL} />
            </Link>
          )}
          <CardHeader date={props.post.frontmatter.date || null}>
            <Link style={{ boxShadow: `none` }} to={props.post.fields.slug}>
              {title}
            </Link>
          </CardHeader>
          <CardContent
            html={props.post.frontmatter.description || props.post.excerpt}
          />
          <CardFooter>
            <Tags
              tags={postTags}
              selectedTags={props.tags}
              updateTags={props.updateTags}
            />
          </CardFooter>
        </article>
      </div>
    </div>
  )
}

export default Card
