import React from "react"
import { PostInterface } from "../../pages/blog"
import { default as BlogCard } from "./card"
import { default as BlogFilter } from "./card-filter"

export interface CardListInterface {
  posts: Array<PostInterface>
  tags: Array<string>
  updateTags: (tags: Array<string>) => void
}

const CardList: React.FunctionComponent<CardListInterface> = props => {
  return (
    <>
      {props.tags.length > 0 && (
        <BlogFilter selectedTags={props.tags} updateTags={props.updateTags} />
      )}
      <div className="flex content-start flex-wrap">
        {props.posts.map((post: PostInterface) => (
          <BlogCard
            key={post.fields.slug}
            post={post}
            tags={props.tags}
            updateTags={props.updateTags}
          />
        ))}
      </div>
    </>
  )
}

export default CardList
